protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [EF9 breaking change] HasIndex now throws for Cosmos entities.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // [EF9 breaking change] Default discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old name so existing documents and direct SQL queries (c.Discriminator) keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // [EF9 breaking change] id values no longer include the discriminator prefix.
        // Existing documents use "Product|123" format; this keeps EF9 generating the same format.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

