using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // [EF9 breaking change] Sync I/O (ToList, SaveChanges, etc.) now throws on the Cosmos provider.
    // All queries and mutations must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — works because we preserved "Discriminator" via HasDiscriminator above.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

